func adminHopStatusLabel(status string) string {
	switch status {
	case types.HopStatusOpen:
		return "Open"
	case types.HopStatusAccepted:
		return "Accepted"
	case types.HopStatusCompleted:
		return "Completed"
	case types.HopStatusCanceled:
		return "Canceled"
	case types.HopStatusExpired:
		return "Expired"
	default:
		raw := strings.TrimSpace(strings.ReplaceAll(status, "_", " "))
		if raw == "" {
			return "Unknown"
		}
		return strings.ToUpper(raw[:1]) + raw[1:]
	}
}

func adminTotalHopCount(counts []types.AdminHopStatusCount) int {
	total := 0
	for _, c := range counts {
		total += c.Count
	}
	return total
}

func adminCanExpireHopStatus(status string) bool {
	return status == types.HopStatusOpen || status == types.HopStatusAccepted
}

func adminCanDeleteHopStatus(status string) bool {
	return status == types.HopStatusOpen || status == types.HopStatusCanceled
}

func adminModerationReportTypeLabel(reportType string) string {
	switch reportType {
	case types.ModerationReportTypeHopComment:
		return "Comment"
	case types.ModerationReportTypeHopImage:
		return "Image"
	default:
		return "Unknown"
	}
}

func adminModerationStatusLabel(status string) string {
	switch status {
	case types.ModerationReportStatusOpen:
		return "Open"
	case types.ModerationReportStatusActioned:
		return "Actioned"
	case types.ModerationReportStatusDismissed:
		return "Dismissed"
	default:
		return "Unknown"
	}
}

func adminModerationStatusBadgeClass(status string) string {
	base := "inline-flex items-center rounded-full px-2 py-0.5 text-xs font-semibold "
	switch status {
	case types.ModerationReportStatusOpen:
		return base + "bg-amber-100 text-amber-800"
	case types.ModerationReportStatusActioned:
		return base + "bg-red-100 text-red-800"
	case types.ModerationReportStatusDismissed:
		return base + "bg-slate-200 text-slate-700"
	default:
		return base + "bg-slate-200 text-slate-700"
	}
}

func adminOrganizationsActionModalData(query string) string {
	return "{" +
		"actionModalOpen: false," +
		"actionModalAction: ''," +
		"actionModalOrgID: ''," +
		"actionModalHopID: ''," +
		"actionModalTitle: ''," +
		"actionModalPrompt: ''," +
		"actionModalConfirmLabel: ''," +
		"actionModalConfirmClass: 'bg-sky-700 hover:bg-sky-800'," +
		"actionModalReason: ''," +
		"actionModalQuery: " + strconv.Quote(strings.TrimSpace(query)) + "," +
		"openActionModal(action, orgID, hopID, title, prompt, confirmLabel, confirmClass) {" +
		"this.actionModalAction = action;" +
		"this.actionModalOrgID = String(orgID);" +
		"this.actionModalHopID = hopID ? String(hopID) : '';" +
		"this.actionModalTitle = title;" +
		"this.actionModalPrompt = prompt;" +
		"this.actionModalConfirmLabel = confirmLabel;" +
		"this.actionModalConfirmClass = confirmClass;" +
		"this.actionModalReason = '';" +
		"this.actionModalOpen = true;" +
		"}," +
		"closeActionModal() {" +
		"this.actionModalOpen = false;" +
		"this.actionModalReason = '';" +
		"}," +
		"}"
}

